// nodes/inputNode.js
import { useState } from 'react';
import { BaseNode, fieldStyle } from './BaseNode';
import { useStore } from '../store';

export const InputNode = ({ id, data }) => {
  const updateNodeField = useStore((s) => s.updateNodeField);
  const [name, setName] = useState(data?.inputName ?? id.replace('customInput-', 'input_'));
  const [type, setType] = useState(data?.inputType ?? 'Text');

  return (
    <BaseNode
      id={id}
      title="Input"
      icon="⬇"
      accentColor="#22d3ee"
      outputs={[{ id: 'value', label: 'value' }]}
    >
      <div style={fieldStyle.group}>
        <label style={fieldStyle.label}>Name</label>
        <input
          style={fieldStyle.input}
          value={name}
          onChange={(e) => {
            setName(e.target.value);
            updateNodeField(id, 'inputName', e.target.value);
          }}
        />
      </div>
      <div style={fieldStyle.group}>
        <label style={fieldStyle.label}>Type</label>
        <select
          style={fieldStyle.select}
          value={type}
          onChange={(e) => {
            setType(e.target.value);
            updateNodeField(id, 'inputType', e.target.value);
          }}
        >
          <option>Text</option>
          <option>File</option>
          <option>Image</option>
          <option>Number</option>
        </select>
      </div>
    </BaseNode>
  );
};
